def normalize_h(h, N):
    """Project h to constraints: h in [0,1], sum(h) = N/2."""
    h = np.clip(h, 0.0, 1.0)
    target = N / 2.0
    for _ in range(100):
        current = np.sum(h)
        if abs(current - target) < 1e-12:
            break
        diff = target - current
        if diff > 0:
            mask = h < 1.0
        else:
            mask = h > 0.0
        count = np.sum(mask)
        if count == 0:
            break
        h[mask] += diff / count
        h = np.clip(h, 0.0, 1.0)
    return h

